+      kind: "systemEvent",
+      text: "tick",
+    },
+    state: {},
+    ...overrides,
+  };
+}
+
+async function migrateLegacyJob(legacyJob: Record<string, unknown>) {
+  const store = await makeStorePath();
+  try {
+    await writeLegacyStore(store.storePath, legacyJob);
+    return await migrateAndLoadFirstJob(store.storePath);
+  } finally {
+    await store.cleanup();
+  }
+}
